def demo_sensor_reading():
    adc = machine.ADC(machine.Pin(34))
    adc.atten(machine.ADC.ATTN_11DB)
    raw = adc.read()
    temperature = 20.0 + (raw / 4095.0) * 15.0
    humidity = 40.0 + (raw / 4095.0) * 30.0
    battery_mv = 3600 + int((raw / 4095.0) * 200)
    return temperature, humidity, battery_mv


